/**
 * 漢字高手 - 遊戲引擎
 * 處理資料載入、篩選、題目產生等核心邏輯
 */
import DB from './hanziDatabase.json';

// ─── 常數 ───────────────────────────────────────────────────────
export const LEVELS = [
  { id: 1, name: '史萊姆', emoji: '🟢', maxFreq: 100,   desc: '前 100 高頻字', color: '#27ae60' },
  { id: 2, name: '食人魔', emoji: '👹', maxFreq: 1100,  desc: '累積前 1,100 字', color: '#e67e22' },
  { id: 3, name: '飛龍',   emoji: '🐉', maxFreq: 2300,  desc: '累積前 2,300 字', color: '#2980b9' },
  { id: 4, name: '巫妖',   emoji: '💀', maxFreq: 3500,  desc: '累積前 3,500 字', color: '#8e44ad' },
  { id: 5, name: '魔王',   emoji: '👑', maxFreq: 99999, desc: '全字庫', color: '#c0392b' },
];

export const TIMERS = [
  { label: '1 分鐘', value: 60,   tag: '極速' },
  { label: '3 分鐘', value: 180,  tag: '' },
  { label: '5 分鐘', value: 300,  tag: '' },
  { label: '15 分鐘', value: 900, tag: '' },
  { label: '無限',   value: 0,    tag: '自行暫停' },
];

export const ALL_RADICALS = DB.radicals;
export const ALL_CHARS = DB.chars;

// ─── 工具函式 ────────────────────────────────────────────────────
export function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export function pickRandom(arr, n, exclude = []) {
  const filtered = arr.filter(x => !exclude.includes(x));
  return shuffle(filtered).slice(0, n);
}

// ─── 篩選字庫 ────────────────────────────────────────────────────
export function filterChars(level, selectedRadicals) {
  const maxFreq = LEVELS.find(l => l.id === level)?.maxFreq || 99999;
  return ALL_CHARS.filter(c =>
    c.freq <= maxFreq && selectedRadicals.has(c.radical)
  );
}

// ─── 隨機選 N 個部首 ─────────────────────────────────────────────
export function randomRadicals(n = 5, level = 1) {
  const maxFreq = LEVELS.find(l => l.id === level)?.maxFreq || 99999;
  // 只從有對應字的部首中選
  const availableRadicals = [...new Set(
    ALL_CHARS.filter(c => c.freq <= maxFreq).map(c => c.radical)
  )];
  return new Set(shuffle(availableRadicals).slice(0, Math.min(n, availableRadicals.length)));
}

// ─── 造詞過濾 ────────────────────────────────────────────────────
// Lv1~3: 造詞中每個字都必須在 Lv3 範圍內
// Lv4: 造詞中每個字都必須在 Lv4 範圍內
// Lv5: 不過濾
const lv3CharSet = new Set(ALL_CHARS.filter(c => c.freq <= 2300).map(c => c.char));
const lv4CharSet = new Set(ALL_CHARS.filter(c => c.freq <= 3500).map(c => c.char));

export function filterWords(item, level) {
  const words = item.words || [];
  if (level >= 5) return words; // 魔王不過濾

  const charSet = level <= 3 ? lv3CharSet : lv4CharSet;
  const maxLen = level <= 4 ? 4 : 999;

  return words.filter(w => {
    if (w.length > maxLen || w.length < 2) return false;
    if (!w.includes(item.char)) return false;
    // 檢查每個字是否在允許範圍內
    for (const ch of w) {
      if (!charSet.has(ch) && ch !== item.char) return false;
    }
    return true;
  });
}

// ─── 產生題目池 ──────────────────────────────────────────────────
export function generateQuizPool(filteredChars, count = 20) {
  // 去重：同一個字只出現一次
  const seen = new Set();
  const unique = [];
  for (const c of shuffle(filteredChars)) {
    if (!seen.has(c.char)) {
      seen.add(c.char);
      unique.push(c);
    }
  }
  return unique.slice(0, count);
}

// ─── 產生單題 ────────────────────────────────────────────────────
// mode: 1=看字選音, 2=看音選字, 3=造詞填空, 0=隨機
export function generateQuestion(item, pool, level, mode = 0) {
  const actualMode = mode === 0 ? [1, 2, 3][Math.floor(Math.random() * 3)] : mode;
  const allChars = ALL_CHARS;

  if (actualMode === 1) {
    // 看漢字選注音 - 4 個選項
    const wrongs = pickRandom(
      allChars.map(h => h.zhuyin),
      3,
      [item.zhuyin, ...(item.readings?.map(r => r.zhuyin) || [])]
    );
    return {
      mode: 1,
      options: shuffle([item.zhuyin, ...wrongs]),
      answer: item.zhuyin,
      wordBlank: null,
    };
  } else if (actualMode === 2) {
    // 看注音選漢字 - 4 個選項
    const wrongs = pickRandom(
      allChars.map(h => h.char),
      3,
      [item.char]
    );
    return {
      mode: 2,
      options: shuffle([item.char, ...wrongs]),
      answer: item.char,
      wordBlank: null,
    };
  } else {
    // 造詞填空
    const validWords = filterWords(item, level);
    let wordBlank = '＿';

    if (validWords.length > 0) {
      const word = validWords[Math.floor(Math.random() * validWords.length)];
      const idx = word.indexOf(item.char);
      if (idx >= 0) {
        wordBlank = word.substring(0, idx) + '＿' + word.substring(idx + 1);
      }
    }

    const wrongs = pickRandom(
      allChars.map(h => h.char),
      3,
      [item.char]
    );
    return {
      mode: 3,
      options: shuffle([item.char, ...wrongs]),
      answer: item.char,
      wordBlank,
    };
  }
}

// ─── 挑戰模式題庫 ───────────────────────────────────────────────
export function generateChallengePool(count) {
  const seen = new Set();
  const unique = [];
  for (const c of shuffle(ALL_CHARS)) {
    if (!seen.has(c.char)) {
      seen.add(c.char);
      unique.push(c);
    }
  }
  return unique.slice(0, Math.min(count, unique.length));
}

// ─── Markdown 匯入解析 ──────────────────────────────────────────
export function parseMarkdownImport(text) {
  const lines = text.trim().split('\n');
  const results = [];

  for (const line of lines) {
    // 跳過標題列和分隔列
    if (line.startsWith('|') && (line.includes('漢字') || line.includes('---'))) continue;

    const cells = line.split('|').map(c => c.trim()).filter(Boolean);
    if (cells.length >= 3) {
      const [char, zhuyin, pinyin, words, radical] = cells;
      if (char && [...char].length === 1 && zhuyin) {
        results.push({
          char,
          zhuyin,
          pinyin: pinyin || '',
          radical: radical || '自訂',
          strokes: 0,
          words: words ? words.split(/[,，、]/).map(w => w.trim()).filter(Boolean) : [],
          freq: 99999,
        });
      }
    }
  }
  return results;
}
